+        Go,
+    }
+    impl From<Event> for QBMsg {
+        fn from(_: Event) -> Self {
+            QBMsg::Step("e")
+        }
+    }
+    impl Model for QuitBatchModel {
+        type Message = QBMsg;
+        fn update(&mut self, msg: QBMsg) -> Cmd<QBMsg> {
